					// 	lat: undefined
					// })
					setPinLocation({
						...pinLocation,
						lon: undefined,
						lat: undefined
					})
				}
			})
		}
		else {
			console.log("geolocation permissions not active")
		}
	}, [pinLocation.open])

	//update main data: connections, topics and tags, drafted posts
	React.useEffect(()=> {
		getConnections();
		getSuggestions();
		getDrafts();
