	//Enter animation
	React.useEffect(()=> {
		let elCurrent = el.current;
		let delay = setTimeout(()=> {
			elCurrent.classList.remove('_enter');	
		}, 200)
	}, [])

	//might need to edit this for update
	const textareaImageAdd = (index, type, info) => {

		if(type == 'text') {
