							<button className={`buttonDefault remove`}
									onClick={(e)=> {
										e.preventDefault();
										console.log(index);
										let copy2 = postContent.filter(post => post.index != index);
										setPostContent(copy2);
									}}>
								Remove
							</button>
						}
						
					</div>
				)
		}
		else if(type == 'media') {

