				</svg>
			</div>

			<form onSubmit={handleSubmit} encType='multipart/form-data'>
				<fieldset>

					<div id="titleWrapper">

						<button id="datePicker" className={`buttonDefault`}>
							{kongetsu}. {kyou}. {kotoshi}
